  function clientCard(l){const h=l.saudeCliente||'Verde';const cls=h==='Verde'?'ok':h==='Amarelo'?'warn':'danger';return `<div class="v6-client-card"><div class="name">${esc(l.nome)}</div><div class="meta">${esc(l.segmento||'—')} · ${esc(l.responsavel||'Sem responsável')}</div><div class="v6-badges"><span class="v6-pill ${cls}"><span class="v6-dot ${cls}"></span>Saúde ${esc(h)}</span><span class="v6-pill blue">${brl(l.valor)}</span>${l.renovacao?`<span class="v6-pill warn">Renovação ${dateBR(l.renovacao)}</span>`:''}</div><div class="v6-section-note"><b>Último contexto:</b> ${esc(l.obs||'Sem observação.')}<br><b>Upsell/cross-sell:</b> ${esc(l.upsell||'Mapear expansão na próxima conversa.')}</div><div class="v6-client-actions"><button class="btn btn-xs" data-v6-client-open="${esc(l.nome)}">Abrir</button><button class="btn btn-xs" data-v6-client-action="follow" data-lead="${esc(l.nome)}">Follow-up</button><button class="btn btn-xs" data-v6-client-action="upsell" data-lead="${esc(l.nome)}">Upsell</button></div></div>`;}
  function clientAction(type,name){const l=safeLeads().find(x=>x.nome===name);if(!l)return;if(type==='follow'){l.followup=addDays(7);l.proximaAcao='Contato de pós-venda / relacionamento';}else{l.proximaAcao='Mapear oportunidade de upsell/cross-sell';l.tags=[l.tags,'upsell'].filter(Boolean).join(', ');}try{typeof addAtividade==='function'&&addAtividade(l.nome,'Nota',l.proximaAcao)}catch(e){};saveAll();toast('Ação criada no cliente');renderV6All();}

  function ensurePlaybookPro(){const page=$('#playbooks');if(!page||$('#v6PlaybookPro'))return;const box=document.createElement('div');box.id='v6PlaybookPro';box.className='v6-card';box.innerHTML=`<div class="v6-card-head"><div><div class="v6-title">Laboratório de scripts e playbooks</div><div class="v6-sub">Use scripts no lead, salve versões e acompanhe desempenho</div></div><div class="v6-toolbar"><button class="btn btn-sm" id="v6PbVersion">Salvar versão do script atual</button></div></div><div class="v6-body"><div class="v6-field-grid"><div class="v6-field"><label>Usar playbook em qual lead?</label><select id="v6PbLead"></select></div><div class="v6-field"><label>Cenário</label><select id="v6PbScenario"><option>Prospecção</option><option>Diagnóstico</option><option>Proposta parada</option><option>Objeção</option><option>Reativação</option><option>Pós-venda</option></select></div></div><div id="v6PbMetrics" style="margin-top:14px"></div></div>`;page.querySelector('.section-header')?.insertAdjacentElement('afterend',box);$('#v6PbVersion').onclick=saveScriptVersion;}
  function renderPlaybookPro(){const sel=$('#v6PbLead');if(sel)sel.innerHTML=safeLeads().map(l=>`<option>${esc(l.nome)}</option>`).join('');const stats=getJSON(LS.playbookStats,{});const total=Object.values(stats).reduce((s,x)=>s+(x.usos||0),0);const box=$('#v6PbMetrics');if(box)box.innerHTML=`<div class="v6-grid v6-grid-3"><div class="v6-kpi"><div class="val">${total}</div><div class="lbl">Usos registrados</div><div class="hint">Clique em “usar” nos scripts ou aplique em um lead.</div></div><div class="v6-kpi"><div class="val">${Object.keys(stats).length}</div><div class="lbl">Playbooks medidos</div><div class="hint">Mede adoção do time.</div></div><div class="v6-kpi"><div class="val">${getJSON(LS.scriptVersions,[]).length}</div><div class="lbl">Versões salvas</div><div class="hint">Comparação de mensagens.</div></div></div>`;enhancePbCards();}
  function enhancePbCards(){$$('.pb-card').forEach((c,i)=>{if($('.v6-card-actions',c))return;const name=$('.pb-name',c)?.textContent||'Playbook';c.insertAdjacentHTML('beforeend',`<div class="v6-card-actions" style="padding:0 18px 14px"><button class="btn btn-xs" data-v6-use-pb="${esc(name)}">Usar no lead</button><button class="btn btn-xs" data-v6-rate-pb="${esc(name)}">Registrar resultado</button></div>`);});$$('[data-v6-use-pb]').forEach(b=>b.onclick=e=>{e.stopPropagation();const lead=$('#v6PbLead')?.value; if(!lead)return toast('Escolha um lead','warn');const l=safeLeads().find(x=>x.nome===lead);if(l){l.proximaAcao='Executar playbook: '+b.dataset.v6UsePb;l.playbookAtual=b.dataset.v6UsePb;try{typeof addAtividade==='function'&&addAtividade(l.nome,'Nota','Playbook aplicado: '+b.dataset.v6UsePb)}catch(err){};const stats=getJSON(LS.playbookStats,{});stats[b.dataset.v6UsePb]={...(stats[b.dataset.v6UsePb]||{}),usos:(stats[b.dataset.v6UsePb]?.usos||0)+1};setJSON(LS.playbookStats,stats);saveAll();toast('Playbook aplicado ao lead');renderV6All();}});$$('[data-v6-rate-pb]').forEach(b=>b.onclick=e=>{e.stopPropagation();const r=prompt('Resultado do playbook (ex: reunião, resposta, venda, sem resposta):','resposta');if(!r)return;const stats=getJSON(LS.playbookStats,{});const k=b.dataset.v6RatePb;stats[k]={...(stats[k]||{}),usos:(stats[k]?.usos||0)+1,resultados:[...(stats[k]?.resultados||[]),{r,dt:new Date().toISOString()}]};setJSON(LS.playbookStats,stats);toast('Resultado registrado');renderPlaybookPro();});}
  function saveScriptVersion(){const versions=getJSON(LS.scriptVersions,[]);versions.unshift({id:'ver_'+Date.now(),data:new Date().toISOString(),cenario:$('#v6PbScenario')?.value||'Prospecção',lead:$('#v6PbLead')?.value||'',texto:$('#aiScriptOutput')?.innerText?.slice(0,4000)||'Versão manual'});setJSON(LS.scriptVersions,versions.slice(0,80));toast('Versão de script salva');renderPlaybookPro();}

  function ensureObjPro(){const page=$('#objecoes');if(!page||$('#v6ObjPro'))return;const box=document.createElement('div');box.id='v6ObjPro';box.className='v6-card';box.innerHTML=`<div class="v6-card-head"><div><div class="v6-title">Objeções conectadas ao lead</div><div class="v6-sub">Ranking, respostas por canal e registro no histórico</div></div></div><div class="v6-body"><div class="v6-field-grid"><div class="v6-field"><label>Lead</label><select id="v6ObjLead"></select></div><div class="v6-field"><label>Objeção</label><select id="v6ObjType"><option>Preço</option><option>Tempo</option><option>Concorrência</option><option>Necessidade</option><option>Autoridade</option><option>Confiança</option></select></div><div class="v6-field"><label>Canal</label><select id="v6ObjChannel"><option>Ligação</option><option>WhatsApp</option><option>E-mail</option><option>Reunião</option></select></div><div class="v6-field"><label>Ação</label><button class="btn btn-primary" id="v6ObjRegister">Registrar objeção no lead</button></div></div><div class="v6-split" style="margin-top:14px"><div id="v6ObjAnswer"></div><div id="v6ObjRank"></div></div></div>`;page.querySelector('.section-header')?.insertAdjacentElement('afterend',box);$('#v6ObjType').onchange=$('#v6ObjChannel').onchange=renderObjPro;$('#v6ObjRegister').onclick=registerObj;}
  function objAnswer(type,canal){const base={Preço:'Entendo. Antes de olhar preço isolado, vale comparar o custo de continuar perdendo follow-ups, reuniões e oportunidades no funil.',Tempo:'Faz sentido. Justamente por isso a proposta é começar com um próximo passo curto, para validar se o ganho compensa o tempo investido.',Concorrência:'Ótimo sinal que vocês já estão comparando opções. Minha sugestão é avaliarmos critérios: rotina comercial, metas, visibilidade do funil e adoção do time.',Necessidade:'Perfeito. Posso te fazer duas perguntas para entender se isso é prioridade agora ou se vale retomar em outro momento?',Autoridade:'Sem problema. Quem além de você precisa participar para avaliarmos impacto e próximos passos?',Confiança:'Compreendo. Podemos começar com um diagnóstico pequeno e evidências práticas antes de qualquer decisão maior.'}[type]||'Vamos entender o contexto antes de responder.';return canal==='WhatsApp'?base.replace('Entendo. ','Entendo.\n\n'):canal==='E-mail'?`Olá [NOME],\n\n${base}\n\nPodemos avançar com uma conversa objetiva?`:base;}
  function renderObjPro(){const leadSel=$('#v6ObjLead');if(leadSel)leadSel.innerHTML=safeLeads().map(l=>`<option>${esc(l.nome)}</option>`).join('');const type=$('#v6ObjType')?.value||'Preço',channel=$('#v6ObjChannel')?.value||'WhatsApp';const ans=$('#v6ObjAnswer');if(ans)ans.innerHTML=`<div class="v6-card" style="box-shadow:none"><div class="v6-card-head"><div><div class="v6-title">Resposta ${esc(channel)}</div><div class="v6-sub">Versão curta + consultiva</div></div><button class="btn btn-sm" id="v6CopyObj">Copiar</button></div><div class="v6-body"><div class="script-text" id="v6ObjText">${esc(objAnswer(type,channel))}</div></div></div>`;$('#v6CopyObj')&&( $('#v6CopyObj').onclick=()=>navigator.clipboard?.writeText($('#v6ObjText')?.innerText||'').then(()=>toast('Resposta copiada')) );const count={};safeLeads().forEach(l=>(l.objecoes||[]).forEach(o=>{count[o.tipo]=(count[o.tipo]||0)+1}));const rank=$('#v6ObjRank');if(rank)rank.innerHTML=`<div class="v6-card" style="box-shadow:none"><div class="v6-card-head"><div><div class="v6-title">Ranking de objeções</div><div class="v6-sub">Registradas nos leads</div></div></div><div class="v6-body"><div class="v6-compact-list">${Object.entries(count).sort((a,b)=>b[1]-a[1]).map(([k,v])=>`<div class="v6-list-row"><b>${esc(k)}</b><span>${v} ocorrência(s)</span></div>`).join('')||'<div class="crm-empty">Nenhuma objeção registrada ainda.</div>'}</div></div></div>`;}
  function registerObj(){const l=safeLeads().find(x=>x.nome===$('#v6ObjLead')?.value);if(!l)return;l.objecoes=l.objecoes||[];l.objecoes.unshift({tipo:$('#v6ObjType')?.value,canal:$('#v6ObjChannel')?.value,resposta:$('#v6ObjText')?.innerText||'',data:new Date().toISOString()});l.proximaAcao='Responder objeção: '+($('#v6ObjType')?.value||'');try{typeof addAtividade==='function'&&addAtividade(l.nome,'Nota','Objeção registrada: '+($('#v6ObjType')?.value||''))}catch(e){};saveAll();toast('Objeção registrada no lead');renderObjPro();}

  function renderLossPro(){const page=$('#perdas');if(!page)return;let box=$('#v6LossPro');if(!box){box=document.createElement('div');box.id='v6LossPro';box.className='v6-card';page.querySelector('.section-header')?.insertAdjacentElement('afterend',box);}const lost=safeLeads().filter(l=>l.etapa==='Perdido');const by={};lost.forEach(l=>{const m=l.motivoPerda||'Não informado';by[m]=(by[m]||0)+1;if(!l.reativarEm)l.reativarEm=reactivationDate(m);});box.innerHTML=`<div class="v6-card-head"><div><div class="v6-title">Plano de perdas e reativação</div><div class="v6-sub">Motivo obrigatório, aprendizado e nova tentativa comercial</div></div><button class="btn btn-sm" id="v6ReactivateDue">Reativar vencidos</button></div><div class="v6-body"><div class="v6-split"><div><table class="v6-table"><thead><tr><th>Motivo</th><th>Ocorrências</th><th>Ação recomendada</th></tr></thead><tbody>${Object.entries(by).map(([m,c])=>`<tr><td>${esc(m)}</td><td>${c}</td><td>${esc(reactivationAction(m))}</td></tr>`).join('')||'<tr><td colspan="3">Nenhuma perda registrada.</td></tr>'}</tbody></table></div><div><div class="v6-title" style="margin-bottom:9px">Fila de reativação</div><div class="v6-compact-list">${lost.slice(0,6).map(l=>`<div class="v6-list-row"><div><b>${esc(l.nome)}</b><br><span>${esc(l.motivoPerda||'Sem motivo')} · reativar ${dateBR(l.reativarEm)}</span></div><button class="btn btn-xs" data-v6-reactivate="${esc(l.nome)}">Reativar</button></div>`).join('')||'<div class="crm-empty">Sem leads perdidos.</div>'}</div></div></div></div>`;$$('[data-v6-reactivate]',box).forEach(b=>b.onclick=()=>reactivateLead(b.dataset.v6Reactivate));$('#v6ReactivateDue').onclick=()=>{lost.filter(l=>!l.reativarEm||l.reativarEm<=today()).forEach(l=>reactivateLead(l.nome,true));toast('Leads vencidos movidos para reativação','success');renderCoreAndV6();};}
  function reactivationDate(m){m=(m||'').toLowerCase();return m.includes('preço')?addDays(60):m.includes('tempo')?addDays(30):m.includes('concorr')?addDays(45):addDays(40)}
  function reactivationAction(m){m=(m||'').toLowerCase();if(m.includes('preço'))return 'Reativar com nova condição, ROI ou pacote menor.';if(m.includes('tempo'))return 'Retomar com pergunta de prioridade e prazo.';if(m.includes('concorr'))return 'Comparar diferenciais e critérios de decisão.';return 'Criar nova hipótese e contato consultivo.'}
  function reactivateLead(name,silent){const l=safeLeads().find(x=>x.nome===name);if(!l)return;l.etapa='Contato';l.followup=today();l.proximaAcao='Reativação: '+reactivationAction(l.motivoPerda);l.tags=[l.tags,'reativação'].filter(Boolean).join(', ');try{typeof addAtividade==='function'&&addAtividade(l.nome,'Automação','Lead reativado a partir de perdas')}catch(e){};saveAll();if(!silent)toast('Lead reativado');renderCoreAndV6();}

  function ensureGoalsImprovements(){const page=$('#metas');if(!page)return;let box=$('#v6GoalsPace');if(!box){box=document.createElement('div');box.id='v6GoalsPace';box.className='v6-card';page.appendChild(box);}renderGoalsPace();}
  function getGoals(){try{return typeof goalsV5!=='undefined'&&Array.isArray(goalsV5)?goalsV5:getJSON('crm_goals_v5',[])}catch(e){return getJSON('crm_goals_v5',[])}}
  function goalReal(g){try{return typeof goalRealized==='function'?goalRealized(g):Number(g.realizado)||0}catch(e){return Number(g.realizado)||0}}
  function renderGoalsPace(){const box=$('#v6GoalsPace');if(!box)return;const goals=getGoals();const now=new Date(today()+'T00:00:00');box.innerHTML=`<div class="v6-card-head"><div><div class="v6-title">Ritmo de metas</div><div class="v6-sub">Quanto falta por dia, semana e responsável</div></div></div><div class="v6-body"><table class="v6-table"><thead><tr><th>Meta</th><th>Responsável</th><th>Período</th><th>Ritmo necessário</th><th>Status</th></tr></thead><tbody>${goals.map(g=>{const alvo=Number(g.alvo)||0,real=goalReal(g),falt=Math.max(0,alvo-real),end=g.fim?new Date(g.fim+'T00:00:00'):now,daysLeft=Math.max(1,Math.ceil((end-now)/86400000)+1),need=Math.ceil(falt/daysLeft);const p=pct(real,alvo);return `<tr><td>${esc(g.titulo||g.tipo||'Meta')}</td><td>${esc(g.responsavel||'Time')}</td><td>${dateBR(g.inicio)} → ${dateBR(g.fim)}</td><td>${need}/dia para bater</td><td><span class="v6-pill ${p>=100?'ok':daysLeft<=3&&p<80?'danger':'warn'}">${p}%</span></td></tr>`}).join('')||'<tr><td colspan="5">Nenhuma meta cadastrada.</td></tr>'}</tbody></table></div>`;}

  /* Cadências/follow-ups removidos da camada V6: módulo único V63 controla a aba #cadencias. */

  function ensureAutomationLab(){const page=$('#automacoes');if(!page||$('#v6AutomationLab'))return;const box=document.createElement('div');box.id='v6AutomationLab';box.className='v6-card';box.innerHTML=`<div class="v6-card-head"><div><div class="v6-title">Construtor Quando / Se / Então</div><div class="v6-sub">Modelos prontos, teste e log de execução</div></div><button class="btn btn-sm" id="v6AutoTest">Testar automações</button></div><div class="v6-body"><div class="v6-field-grid"><div class="v6-field"><label>Quando</label><select id="v6AutoWhen"><option>Lead mudar de etapa</option><option>Follow-up vencer</option><option>Lead ficar parado</option><option>Meta ficar atrasada</option></select></div><div class="v6-field"><label>Se</label><select id="v6AutoIf"><option>Etapa for Proposta</option><option>Sem próxima ação</option><option>Score maior que 80</option><option>Motivo de perda existir</option></select></div><div class="v6-field"><label>Então</label><select id="v6AutoThen"><option>Criar follow-up em 2 dias</option><option>Registrar alerta no histórico</option><option>Aplicar tag urgente</option><option>Enviar para reativação</option></select></div><div class="v6-field"><label>Ação</label><button class="btn btn-primary" id="v6AutoCreate">Criar modelo</button></div></div><div class="v6-split" style="margin-top:14px"><div id="v6AutoTemplates"></div><div><div class="v6-title" style="margin-bottom:8px">Log de execução</div><div id="v6AutoLog" class="v6-log"></div></div></div></div>`;page.querySelector('.section-header')?.insertAdjacentElement('afterend',box);$('#v6AutoCreate').onclick=createAutoTemplate;$('#v6AutoTest').onclick=testAutomations;renderAutomationLab();}
  function logAuto(text){const logs=getJSON(LS.automationLogs,[]);logs.unshift({text,dt:new Date().toISOString()});setJSON(LS.automationLogs,logs.slice(0,80));}
  function createAutoTemplate(){logAuto(`Modelo criado: ${$('#v6AutoWhen')?.value} / ${$('#v6AutoIf')?.value} / ${$('#v6AutoThen')?.value}`);toast('Modelo de automação criado');renderAutomationLab();}
  function testAutomations(){const candidates=safeLeads().filter(l=>!['Fechado','Perdido'].includes(l.etapa)).slice(0,5);candidates.forEach(l=>{if(!l.proximaAcao){l.proximaAcao='Automação: criar próximo follow-up';l.followup=l.followup||addDays(2);logAuto(`Follow-up criado para ${l.nome}`);}});saveAll();toast('Teste executado');renderCoreAndV6();}
  function renderAutomationLab(){const tmpl=$('#v6AutoTemplates');if(tmpl)tmpl.innerHTML=`<div class="v6-card" style="box-shadow:none"><div class="v6-card-head"><div><div class="v6-title">Modelos recomendados</div><div class="v6-sub">Prontos para o fluxo comercial</div></div></div><div class="v6-body"><div class="v6-compact-list">${['Proposta parada → follow-up em 2 dias','Perdido com preço → reativar em 60 dias','Lead sem follow-up → criar tarefa hoje','Score alto sem reunião → alerta para gestor'].map(x=>`<div class="v6-list-row"><b>${esc(x)}</b><span class="v6-pill ok">Ativo</span></div>`).join('')}</div></div></div>`;const log=$('#v6AutoLog');if(log){const logs=getJSON(LS.automationLogs,[]);log.innerHTML=logs.map(l=>`<div class="v6-log-item">${esc(l.text)}<small>${new Date(l.dt).toLocaleString('pt-BR')}</small></div>`).join('')||'<div class="crm-empty">Nenhuma execução registrada.</div>';}}

  function ensureAgendaPro(){const page=$('#agenda');if(!page||$('#v6AgendaPro'))return;const box=document.createElement('div');box.id='v6AgendaPro';box.className='v6-card';box.innerHTML=`<div class="v6-card-head"><div><div class="v6-title">Reunião comercial completa</div><div class="v6-sub">Checklist antes da reunião e pós-reunião obrigatório</div></div></div><div class="v6-body"><div class="v6-field-grid"><div class="v6-field"><label>Lead</label><select id="v6AgendaLead"></select></div><div class="v6-field"><label>Resultado</label><select id="v6MeetingResult"><option>Agendada</option><option>Realizada com avanço</option><option>Realizada sem fit</option><option>Remarcar</option><option>Enviar proposta</option></select></div><div class="v6-field full"><label>Checklist pré-reunião</label><div class="v6-check-grid"><label class="v6-check"><input type="checkbox"> Dor confirmada</label><label class="v6-check"><input type="checkbox"> Decisor identificado</label><label class="v6-check"><input type="checkbox"> Objetivo claro</label><label class="v6-check"><input type="checkbox"> Objeções prováveis</label><label class="v6-check"><input type="checkbox"> Próximo passo preparado</label><label class="v6-check"><input type="checkbox"> Proposta/diagnóstico pronto</label></div></div><div class="v6-field full"><label>Resumo pós-reunião</label><textarea id="v6MeetingNotes" placeholder="O que aconteceu, objeções, decisão e próximo passo..."></textarea></div></div><div class="v6-toolbar" style="margin-top:12px"><button class="btn btn-primary" id="v6SaveMeeting">Salvar pós-reunião</button><button class="btn" id="v6CreateMeetingFollow">Criar follow-up em 2 dias</button></div></div>`;page.querySelector('.section-header')?.insertAdjacentElement('afterend',box);$('#v6SaveMeeting').onclick=saveMeeting;$('#v6CreateMeetingFollow').onclick=()=>{const l=safeLeads().find(x=>x.nome===$('#v6AgendaLead')?.value);if(l){l.followup=addDays(2);l.proximaAcao='Follow-up pós-reunião';saveAll();toast('Follow-up criado');renderCoreAndV6();}};}
