  function saveMeeting(){const l=safeLeads().find(x=>x.nome===$('#v6AgendaLead')?.value);if(!l)return;const result=$('#v6MeetingResult')?.value||'Reunião';const notes=$('#v6MeetingNotes')?.value||'';l.ultimaReuniao=today();l.proximaAcao=result==='Enviar proposta'?'Enviar proposta e definir prazo de decisão':'Definir próximo passo pós-reunião';if(result==='Enviar proposta')l.etapa='Proposta';try{typeof addAtividade==='function'&&addAtividade(l.nome,'Reunião',`${result}. ${notes}`)}catch(e){};saveAll();$('#v6MeetingNotes').value='';toast('Pós-reunião salvo');renderCoreAndV6();}

  function ensureMetricsPro(){const page=$('#metricas');if(!page||$('#v6MetricsPro'))return;const box=document.createElement('div');box.id='v6MetricsPro';box.className='v6-card';box.innerHTML=`<div class="v6-card-head"><div><div class="v6-title">Análise operacional</div><div class="v6-sub">Atividades x resultado, origem e responsável</div></div><div class="v6-toolbar"><select class="v6-filter" id="v6MetricPeriod"><option value="7">7 dias</option><option value="30" selected>30 dias</option><option value="90">90 dias</option></select><button class="btn btn-sm" id="v6MetricPdf">PDF executivo</button></div></div><div class="v6-body" id="v6MetricsBody"></div>`;page.querySelector('.section-header')?.insertAdjacentElement('afterend',box);$('#v6MetricPeriod').onchange=renderMetricsPro;$('#v6MetricPdf').onclick=openExecutiveReport;}
  function renderMetricsPro(){const body=$('#v6MetricsBody');if(!body)return;const list=safeLeads();const byOrig={};const byResp={};list.forEach(l=>{byOrig[l.origem||'Sem origem']=(byOrig[l.origem||'Sem origem']||0)+1;byResp[l.responsavel||'Sem responsável']=(byResp[l.responsavel||'Sem responsável']||0)+1;});const act=list.reduce((a,l)=>a+(Array.isArray(l.atividades)?l.atividades.length:0),0);const meetings=list.filter(l=>Array.isArray(l.atividades)&&l.atividades.some(a=>a.tipo==='Reunião')).length;const won=list.filter(l=>l.etapa==='Fechado').length;body.innerHTML=`<div class="v6-grid v6-grid-4"><div class="v6-kpi"><div class="val">${act}</div><div class="lbl">Atividades registradas</div><div class="hint">Ligações, WhatsApp, reuniões e notas.</div></div><div class="v6-kpi"><div class="val">${meetings}</div><div class="lbl">Leads com reunião</div><div class="hint">Base com avanço consultivo.</div></div><div class="v6-kpi"><div class="val">${pct(won,list.length)}%</div><div class="lbl">Conversão geral</div><div class="hint">Fechados sobre total.</div></div><div class="v6-kpi"><div class="val">${brl(won?list.filter(l=>l.etapa==='Fechado').reduce((s,l)=>s+(Number(l.valor)||0),0)/won:0)}</div><div class="lbl">Ticket médio</div><div class="hint">Receita fechada média.</div></div></div><div class="v6-split" style="margin-top:14px"><div class="v6-card" style="box-shadow:none"><div class="v6-card-head"><div class="v6-title">Conversão por origem</div></div><div class="v6-body v6-mini-bars">${miniBars(byOrig,list.length)}</div></div><div class="v6-card" style="box-shadow:none"><div class="v6-card-head"><div class="v6-title">Ranking por responsável</div></div><div class="v6-body v6-mini-bars">${miniBars(byResp,list.length)}</div></div></div>`;}
  function miniBars(obj,total){return Object.entries(obj).sort((a,b)=>b[1]-a[1]).map(([k,v])=>`<div class="v6-mini-bar"><span>${esc(k)}</span><div class="track"><div class="fill" style="width:${pct(v,total||1)}%"></div></div><strong>${v}</strong></div>`).join('')||'<div class="crm-empty">Sem dados.</div>';}

  function ensureDashboardPro(){const page=$('#dashboard');if(!page||$('#v6DashboardPro'))return;const box=document.createElement('div');box.id='v6DashboardPro';box.className='v6-card';box.innerHTML=`<div class="v6-card-head"><div><div class="v6-title">Diagnóstico executivo</div><div class="v6-sub">Resumo para gestão, diretoria ou reunião semanal</div></div><div class="v6-toolbar"><select class="v6-filter" id="v6DashResp"><option value="">Todos responsáveis</option></select><select class="v6-filter" id="v6DashOrig"><option value="">Todas origens</option></select><button class="btn btn-sm btn-primary" id="v6DashPdf">Gerar PDF</button></div></div><div class="v6-body" id="v6DashBody"></div>`;page.querySelector('.section-header')?.insertAdjacentElement('afterend',box);$('#v6DashPdf').onclick=openExecutiveReport;$('#v6DashResp').onchange=renderDashboardPro;$('#v6DashOrig').onchange=renderDashboardPro;}
  function renderDashboardPro(){const r=$('#v6DashResp'),o=$('#v6DashOrig');if(r)r.innerHTML='<option value="">Todos responsáveis</option>'+getResponsaveis().map(x=>`<option ${r.value===x?'selected':''}>${esc(x)}</option>`).join('');if(o)o.innerHTML='<option value="">Todas origens</option>'+getOrigens().map(x=>`<option ${o.value===x?'selected':''}>${esc(x)}</option>`).join('');let list=safeLeads();if(r?.value)list=list.filter(l=>l.responsavel===r.value);if(o?.value)list=list.filter(l=>l.origem===o.value);const open=list.filter(l=>!['Fechado','Perdido'].includes(l.etapa));const forecast=open.reduce((s,l)=>s+(Number(l.valor)||0)*((Number(l.probabilidade)||PROB[l.etapa]||0)/100),0);const stagnant=open.filter(l=>days(l.ultimaAtualizacao||l.dataEntrada)>=7);const body=$('#v6DashBody');if(body)body.innerHTML=`<div class="v6-grid v6-grid-4"><div class="v6-kpi"><div class="val">${brl(forecast)}</div><div class="lbl">Forecast ponderado</div><div class="hint">Oportunidades abertas x probabilidade.</div></div><div class="v6-kpi"><div class="val">${stagnant.length}</div><div class="lbl">Riscos no funil</div><div class="hint">Leads parados há 7+ dias.</div></div><div class="v6-kpi"><div class="val">${list.filter(l=>l.etapa==='Fechado').length}</div><div class="lbl">Fechamentos</div><div class="hint">Resultado dentro do filtro.</div></div><div class="v6-kpi"><div class="val">${list.filter(l=>l.etapa==='Perdido').length}</div><div class="lbl">Perdas</div><div class="hint">Aprendizado comercial.</div></div></div><div class="v6-alert-list" style="margin-top:14px">${dashboardAlerts(list).map(a=>`<div class="v6-alert"><div><b>${esc(a.t)}</b><p>${esc(a.p)}</p></div><span class="v6-pill ${a.kind}">${esc(a.label)}</span></div>`).join('')}</div>`;}
  function dashboardAlerts(list){const arr=[];const prop=list.filter(l=>l.etapa==='Proposta');const stale=list.filter(l=>!['Fechado','Perdido'].includes(l.etapa)&&days(l.ultimaAtualizacao||l.dataEntrada)>=7);if(prop.length)arr.push({t:'Propostas abertas precisam de prazo',p:`Existem ${prop.length} proposta(s). Confirme decisor, urgência e data de decisão.`,kind:'warn',label:'Atenção'});if(stale.length)arr.push({t:'Funil com oportunidades paradas',p:`${stale.length} lead(s) sem atualização recente. Priorize follow-up.`,kind:'danger',label:'Risco'});if(!arr.length)arr.push({t:'Funil sem alerta crítico',p:'Continue monitorando atividades e metas semanais.',kind:'ok',label:'OK'});arr.push({t:'Próximo passo recomendado',p:'Use metas diárias de atividade e follow-ups por etapa para manter previsibilidade.',kind:'blue',label:'Plano'});return arr;}

  function ensureChatPro(){const page=$('#chat');if(!page||$('#v6ChatPro'))return;const panel=document.createElement('div');panel.id='v6ChatPro';panel.className='v6-card';panel.style.marginBottom='12px';panel.innerHTML=`<div class="v6-card-head"><div><div class="v6-title">Respostas rápidas comerciais</div><div class="v6-sub">Use Playbook, crie follow-up e registre histórico no lead</div></div></div><div class="v6-body"><div class="v6-chat-panel"><div><div class="v6-script-tabs"><button class="v6-script-tab active" data-v6-chat-template="prospec">Prospecção</button><button class="v6-script-tab" data-v6-chat-template="objecao">Objeção</button><button class="v6-script-tab" data-v6-chat-template="follow">Follow-up</button><button class="v6-script-tab" data-v6-chat-template="reuniao">Reunião</button></div><textarea id="v6ChatText" class="spin-textarea" style="min-height:84px"></textarea></div><div><div class="v6-field"><label>Vincular ao lead</label><select id="v6ChatLead"></select></div><div class="v6-toolbar" style="margin-top:10px"><button class="btn btn-sm" id="v6ChatCopy">Copiar</button><button class="btn btn-sm" id="v6ChatFollow">Criar follow-up</button><button class="btn btn-sm" id="v6ChatHist">Registrar no histórico</button></div></div></div></div>`;const layout=$('#chatLayout')||page.firstElementChild;layout?.parentNode?.insertBefore(panel,layout);$$('[data-v6-chat-template]',panel).forEach(b=>b.onclick=()=>{$$('[data-v6-chat-template]',panel).forEach(x=>x.classList.toggle('active',x===b));renderChatTemplate(b.dataset.v6ChatTemplate);});$('#v6ChatCopy').onclick=()=>navigator.clipboard?.writeText($('#v6ChatText')?.value||'').then(()=>toast('Mensagem copiada'));$('#v6ChatFollow').onclick=()=>{const l=safeLeads().find(x=>x.nome===$('#v6ChatLead')?.value);if(l){l.followup=addDays(2);l.proximaAcao='Follow-up de conversa no WhatsApp';saveAll();toast('Follow-up criado');}};$('#v6ChatHist').onclick=()=>{const l=safeLeads().find(x=>x.nome===$('#v6ChatLead')?.value);if(l){try{typeof addAtividade==='function'&&addAtividade(l.nome,'WhatsApp',$('#v6ChatText')?.value||'Mensagem rápida')}catch(e){};saveAll();toast('Histórico registrado');}};}
  function renderChatPro(){const sel=$('#v6ChatLead');if(sel)sel.innerHTML=safeLeads().map(l=>`<option>${esc(l.nome)}</option>`).join('');renderChatTemplate($('.v6-script-tab.active')?.dataset.v6ChatTemplate||'prospec');}
  function renderChatTemplate(t){const lead=safeLeads().find(l=>l.nome===$('#v6ChatLead')?.value)||safeLeads()[0]||{};const map={prospec:`Oi ${lead.nome||'[NOME]'}, tudo bem?\n\nEstou entrando em contato porque acredito que vocês podem ganhar previsibilidade comercial organizando próximos passos, metas e follow-ups. Faz sentido eu te mandar uma ideia objetiva?`,objecao:`Entendo seu ponto. Antes de olhar isso isoladamente, vale avaliarmos o impacto de continuar sem previsibilidade no funil. Posso te fazer duas perguntas rápidas?`,follow:`Oi ${lead.nome||'[NOME]'}, passando para retomar nosso último contato. Você prefere que eu te envie os próximos passos por aqui ou marcamos 15 minutos?`,reuniao:`Perfeito. Para nossa conversa ser objetiva, vou levar três pontos: contexto atual, gargalos de follow-up e plano de próximos passos. Pode ser?`};$('#v6ChatText')&&($('#v6ChatText').value=map[t]||map.prospec);}

  function ensureImportPro(){const page=$('#importar');if(!page||$('#v6ImportPro'))return;const box=document.createElement('div');box.id='v6ImportPro';box.className='v6-card';box.innerHTML=`<div class="v6-card-head"><div><div class="v6-title">Importação segura</div><div class="v6-sub">Modelo de CSV, prévia, mapeamento e confirmação forte</div></div><div class="v6-toolbar"><button class="btn btn-sm" id="v6CsvTemplate">Baixar modelo CSV</button><button class="btn btn-sm" id="v6Backup">Backup JSON</button></div></div><div class="v6-body"><div class="v6-field-grid"><div class="v6-field full"><label>Pré-visualizar CSV</label><textarea id="v6CsvPaste" placeholder="Cole aqui algumas linhas do CSV antes de importar..."></textarea></div></div><div class="v6-toolbar" style="margin-top:10px"><button class="btn btn-sm" id="v6PreviewCsv">Pré-visualizar</button><button class="btn btn-sm btn-danger" id="v6StrongClear">Limpar com confirmação</button></div><div id="v6ImportPreview" class="v6-import-preview" style="margin-top:12px;display:none"></div></div>`;page.querySelector('.section-header')?.insertAdjacentElement('afterend',box);$('#v6CsvTemplate').onclick=downloadCsvTemplate;$('#v6Backup').onclick=downloadBackup;$('#v6PreviewCsv').onclick=previewCsv;$('#v6StrongClear').onclick=strongClear;}
  function downloadFile(name,text,type='text/plain'){const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([text],{type}));a.download=name;a.click();setTimeout(()=>URL.revokeObjectURL(a.href),1000)}
